(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Cybersecurity Awareness for Business', 'cybersecurity-awareness-business', 'Protect your organization from cyber threats with practical security awareness training.', 'This comprehensive program covers essential cybersecurity practices for employees at all levels. Participants will learn to identify phishing attacks, manage passwords securely, handle sensitive data, and respond to security incidents.', 'Equip employees with practical cybersecurity skills to protect organizational assets.', 'All employees, IT staff, managers', 'hybrid', 2, 16, 1200.00, 18000.00, 'English', 30, 'Kuala Lumpur', 'Selangor', 'f5726a06-e1ca-4aa5-88f5-be52d931c1e2', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Digital Marketing: Social Media Strategy', 'digital-marketing-social-media', 'Master social media marketing strategies to grow your brand and drive engagement.', 'Learn to create winning social media strategies across Facebook, Instagram, LinkedIn, and TikTok. Covers content creation, paid advertising, analytics, and ROI measurement.', 'Develop social media marketing strategies that drive measurable business results.', 'Marketing professionals, business owners, brand managers', 'online', 3, 24, 1500.00, 22000.00, 'English', 25, 'Kuala Lumpur', 'Kuala Lumpur', 'b7ba8b5d-37ff-41a2-97ce-6187595fb270', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'ISO 9001:2015 Quality Management System', 'iso-9001-quality-management', 'Implement and maintain ISO 9001:2015 quality management systems.', 'Comprehensive training on ISO 9001:2015 requirements, implementation, and internal auditing. Covers quality policy, process mapping, risk-based thinking, and continual improvement.', 'Enable participants to implement and audit ISO 9001:2015 quality management systems.', 'Quality managers, process improvement teams, internal auditors', 'physical', 3, 24, 2000.00, 30000.00, 'English', 20, 'Petaling Jaya', 'Selangor', '196a1f93-a5d5-43bd-af53-bc4d0e87c120', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Cloud Computing Fundamentals with AWS', 'cloud-computing-aws-fundamentals', 'Get started with cloud computing using Amazon Web Services.', 'Hands-on program introducing cloud computing concepts and AWS services. Covers EC2, S3, RDS, Lambda, and basic cloud architecture.', 'Provide practical cloud computing skills using AWS for IT professionals.', 'IT professionals, developers, system administrators', 'hybrid', 4, 32, 2500.00, 35000.00, 'English', 20, 'Cyberjaya', 'Selangor', 'cc67b663-db85-4a43-b8f0-ced4d6820a39', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Performance Management and KPI Development', 'performance-management-kpi', 'Design effective performance management systems and meaningful KPIs.', 'Create performance management frameworks that drive engagement and success. Covers OKRs, SMART goals, KPI development, performance reviews, and managing underperformance.', 'Equip HR professionals and managers with modern performance management tools.', 'HR managers, line managers, team leaders', 'physical', 2, 16, 1400.00, 20000.00, 'English', 25, 'Kuala Lumpur', 'Kuala Lumpur', '16c86499-f10f-4a09-b47e-aaee92fe3889', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Content Marketing Strategy and Execution', 'content-marketing-strategy', 'Build a content marketing engine that attracts, engages, and converts.', 'From strategy to execution covering content strategy, SEO writing, blog management, email marketing, video content, and measuring content ROI.', 'Plan, create, and measure effective content marketing campaigns.', 'Marketing managers, content creators, business owners', 'online', 2, 16, 1100.00, 16000.00, 'English', 30, 'Kuala Lumpur', 'Kuala Lumpur', 'c85002ce-9490-4d1d-a26a-d8b2d73fbba3', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'Fire Safety and Emergency Response Planning', 'fire-safety-emergency-response', 'Comprehensive fire safety training covering prevention, response, and emergency planning.', 'BOMBA-aligned program covering fire prevention, extinguisher operation, evacuation procedures, emergency response planning, and first aid for burns.', 'Prepare employees to prevent fires and respond to emergencies per Malaysian regulations.', 'Safety officers, facility managers, all employees', 'physical', 1, 8, 600.00, 8000.00, 'Bilingual', 40, 'Shah Alam', 'Selangor', '694cdd4a-f2ba-42e8-8718-f77736408fb3', true, 'published', NOW(), NOW()),
(uuid_generate_v4(), 'c926970b-7861-4a30-aa33-a3c29145dec8', 'CRM Strategy and Customer Experience Excellence', 'crm-customer-experience', 'Transform customer relationships with effective CRM and world-class customer experience.', 'Implement CRM strategies that improve retention, satisfaction, and lifetime value. Covers CRM system selection, customer journey mapping, personalization, and complaint handling.', 'Build lasting customer relationships through effective CRM and CX practices.', 'Sales managers, customer service teams, business development', 'hybrid', 2, 16, 1300.00, 19000.00, 'English', 25, 'Petaling Jaya', 'Selangor', '7d0750d4-6d46-44b8-a88a-cc1975ad9ab7', true, 'published', NOW(), NOW());
